func devbuildRerunUsage() {
	// Header with flags
	fmt.Fprintf(os.Stderr, "%s [flags] devbuild rerun", os.Args[0])
	fmt.Fprint(os.Stderr, " -id INT")
	fmt.Fprint(os.Stderr, " -dryrun BOOL")
	fmt.Fprintln(os.Stderr)

	// Description
	fmt.Fprintln(os.Stderr)
	fmt.Fprintln(os.Stderr, `Rerun devbuild`)

	// Flags list
	fmt.Fprintln(os.Stderr, `    -id INT: ID of build`)
	fmt.Fprintln(os.Stderr, `    -dryrun BOOL: `)

	fmt.Fprintln(os.Stderr)
	fmt.Fprintln(os.Stderr, "Example:")
	fmt.Fprintf(os.Stderr, "    %s %s\n", os.Args[0], "devbuild rerun --id 1 --dryrun true")
}

// hotfixUsage displays the usage of the hotfix command and its subcommands.
func hotfixUsage() {
	fmt.Fprintln(os.Stderr, `The hotfix service provides operations to manage hotfix git tags.`)
	fmt.Fprintf(os.Stderr, "Usage:\n    %s [globalflags] hotfix COMMAND [flags]\n\n", os.Args[0])
	fmt.Fprintln(os.Stderr, "COMMAND:")
	fmt.Fprintln(os.Stderr, `    bump-tag-for-tidbx: Create a hot fix git tag for a GitHub repository`)
	fmt.Fprintln(os.Stderr, `    query-tag-of-tidbx: Query tag info of tidbx repo`)
	fmt.Fprintln(os.Stderr)
	fmt.Fprintln(os.Stderr, "Additional help:")
	fmt.Fprintf(os.Stderr, "    %s hotfix COMMAND --help\n", os.Args[0])
}
func hotfixBumpTagForTidbxUsage() {
	// Header with flags
	fmt.Fprintf(os.Stderr, "%s [flags] hotfix bump-tag-for-tidbx", os.Args[0])
	fmt.Fprint(os.Stderr, " -body JSON")
	fmt.Fprintln(os.Stderr)

	// Description
	fmt.Fprintln(os.Stderr)
	fmt.Fprintln(os.Stderr, `Create a hot fix git tag for a GitHub repository`)

	// Flags list
	fmt.Fprintln(os.Stderr, `    -body JSON: `)

	fmt.Fprintln(os.Stderr)
	fmt.Fprintln(os.Stderr, "Example:")
	fmt.Fprintf(os.Stderr, "    %s %s\n", os.Args[0], "hotfix bump-tag-for-tidbx --body '{\n      \"author\": \"abc@test.com\",\n      \"branch\": \"release-8.5\",\n      \"commit\": \"abc123def456\",\n      \"meta\": {\n         \"ops_req\": {\n            \"applicant\": \"tidb\",\n            \"change_id\": \"c1\",\n            \"release_id\": \"r1\"\n         }\n      },\n      \"repo\": \"pingcap/tidb\"\n   }'")
}

func hotfixQueryTagOfTidbxUsage() {
	// Header with flags
	fmt.Fprintf(os.Stderr, "%s [flags] hotfix query-tag-of-tidbx", os.Args[0])
	fmt.Fprint(os.Stderr, " -repo STRING")
	fmt.Fprint(os.Stderr, " -tag STRING")
	fmt.Fprintln(os.Stderr)

	// Description
	fmt.Fprintln(os.Stderr)
	fmt.Fprintln(os.Stderr, `Query tag info of tidbx repo`)

	// Flags list
	fmt.Fprintln(os.Stderr, `    -repo STRING: `)
	fmt.Fprintln(os.Stderr, `    -tag STRING: `)

	fmt.Fprintln(os.Stderr)
	fmt.Fprintln(os.Stderr, "Example:")
	fmt.Fprintf(os.Stderr, "    %s %s\n", os.Args[0], "hotfix query-tag-of-tidbx --repo \"pingcap/tidb\" --tag \"v26.3.1-nextgen\"")
}
